{
  "layer": "bot",
  "spacing": 0,
  "height": 0,
  "margin-bottom": 0,
  "margin-top": 4,
  "position": "top",
  "margin-right": 4,
  "margin-left": 4,
  "modules-left": [
    "hyprland/workspaces",
    "sway/workspaces"
  ],
  "modules-right": [
    "cpu",
    "custom/gpu",
    "memory",
    "network",
    "battery",
    "pulseaudio",
    "tray",
    "clock"
  ],
  "hyprland/workspaces": {
    "disable-scroll": true,
    "all-outputs": false,
    "tooltip": false
  },
  "sway/workspaces": {
    "disable-scroll": true,
    "all-outputs": false,
    "tooltip": false
  },
  "custom/applauncher": {
    "format": " ",
    "on-click": "pgrep wofi >/dev/null 2>&1 && killall wofi || wofi --show drun --location=top -y 15",
    "tooltip": false
  },
  "tray": {
    "spacing": 10,
    "tooltip": false
  },
  "clock": {
    "format": "󰅐  {:%H:%M}",
    "tooltip": false
  },
  "network": {
    "format-wifi": "   {bandwidthDownBits}",
    "format-ethernet": "   {bandwidthDownBits}",
    "format-disconnected": "󰤮   No Network",
    "interval": 5,
    "tooltip": false
  },
  "pulseaudio": {
      "scroll-step": 5,
      "format": "{icon} {volume}%",
      "format-muted": "  Muted",
      "format-icons": {
          "default": ["", "", " "]
      },
      "on-click": "yad --scale --title='VolumeSlider' --no-buttons --width=200 --height=20 --undecorated --mouse --on-top --close-on-unfocus --print-partial --value=$(wpctl get-volume @DEFAULT_AUDIO_SINK@ | awk '{print $2*100}') | xargs -I {} wpctl set-volume @DEFAULT_AUDIO_SINK@ {}%"
  },
  "cpu": {
    "format": "  {usage}%",
    "interval": 3,
    "tooltip": false
  },
  "custom/gpu": {
    "exec": "bash -c 'if command -v nvidia-smi >/dev/null 2>&1; then LINE=$(nvidia-smi --query-gpu=utilization.gpu,temperature.gpu --format=csv,noheader,nounits | head -n1); echo \"GPU ${LINE/,/ % }°C\"; elif [ -r /sys/class/drm/card0/device/gpu_busy_percent ]; then util=$(cat /sys/class/drm/card0/device/gpu_busy_percent || echo 0); temp=$(cat /sys/class/thermal/thermal_zone*/temp 2>/dev/null | head -n1 || echo 0); temp=$((temp/1000)); echo \"GPU ${util}% ${temp}°C\"; else echo \"GPU N/A\"; fi'",
    "interval": 5,
    "tooltip": false
  },
  "memory": {
    "format": "  {usedPercent}%",
    "interval": 5,
    "tooltip": false
  },
  "battery": {
    "states": {
      "warning": 30,
      "critical": 15
    },
    "format": "{icon} {capacity}%",
    "format-charging": "󰂄 {capacity}%",
    "format-plugged": "󰂄{capacity}%",
    "format-alt": "{icon} {time}",
    "format-full": "󱈑 {capacity}%",
    "format-icons": [
      "󱊡",
      "󱊢",
      "󱊣"
    ]
  }
}

